const limpiarNumero = (valor) => {
  if (typeof valor === 'number') return valor;
  if (!valor || valor === "-") return 0;
  let limpio = valor.toString().replace(/,/g, '').replace('$', '');
  return parseFloat(limpio) || 0;
};

const excelDateToISO = (serial) => {
  if (!serial || isNaN(serial)) return serial;
  if (typeof serial === 'number' && serial > 30000) {
    return new Date(Math.round((serial - 25569) * 86400 * 1000)).toISOString().split('T')[0];
  }
  return serial;
};

const body = $node["Webhook Trigger"].json.body || {};

// Procesamos todos los ítems recibidos del nodo anterior
const items = $input.all();
const processedItems = items.map(item => {
  const row = item.json;
  return {
    banco: body.banco || 'BANCO_DEMO',
    mes: body.mes || 'ACTUAL',
    anio: body.anio || 2026,
    fuente: (body.fuente || 'EXTRACTO').toUpperCase(),
    fecha: excelDateToISO(row.fecha || row.FECHA || new Date().toISOString()),
    descripcion: row.descripcion || row.DESCRIPCIÓN || row.detalle || 'SIN DESCRIPCIÓN',
    valor: limpiarNumero(row.valor || row.VALOR || row.monto || row.MONTO),
    identificacion: row.identificacion || row.IDENTIFICACIÓN || 'N/A',
    referencia: row.referencia || row.REFERENCIA || '',
    nombre_archivo: body.nombre_archivo || 'archivo_desconocido.xlsx'
  };
});

return { processedItems };
